-- Create "outsourcing_orders" table
CREATE TABLE "outsourcing_orders" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "outsourcing_order_no" character varying NOT NULL,
  "supplier_snapshot" jsonb NULL,
  "source_order_no" character varying NULL,
  "source_sales_order_id" bigint NULL,
  "order_date" timestamptz NOT NULL,
  "expected_return_date" timestamptz NULL,
  "lifecycle_status" character varying NOT NULL DEFAULT 'draft',
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "supplier_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "outsourcing_orders_suppliers_outsourcing_orders" FOREIGN KEY ("supplier_id") REFERENCES "suppliers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_orders_lifecycle_status_allowed" CHECK ((lifecycle_status)::text = ANY ((ARRAY['draft'::character varying, 'submitted'::character varying, 'confirmed'::character varying, 'closed'::character varying, 'canceled'::character varying])::text[]))
);
-- Create index "outsourcingorder_expected_return_date" to table: "outsourcing_orders"
CREATE INDEX "outsourcingorder_expected_return_date" ON "outsourcing_orders" ("expected_return_date");
-- Create index "outsourcingorder_lifecycle_status" to table: "outsourcing_orders"
CREATE INDEX "outsourcingorder_lifecycle_status" ON "outsourcing_orders" ("lifecycle_status");
-- Create index "outsourcingorder_order_date" to table: "outsourcing_orders"
CREATE INDEX "outsourcingorder_order_date" ON "outsourcing_orders" ("order_date");
-- Create index "outsourcingorder_outsourcing_order_no" to table: "outsourcing_orders"
CREATE UNIQUE INDEX "outsourcingorder_outsourcing_order_no" ON "outsourcing_orders" ("outsourcing_order_no");
-- Create index "outsourcingorder_source_order_no" to table: "outsourcing_orders"
CREATE INDEX "outsourcingorder_source_order_no" ON "outsourcing_orders" ("source_order_no");
-- Create index "outsourcingorder_source_sales_order_id" to table: "outsourcing_orders"
CREATE INDEX "outsourcingorder_source_sales_order_id" ON "outsourcing_orders" ("source_sales_order_id");
-- Create index "outsourcingorder_supplier_id" to table: "outsourcing_orders"
CREATE INDEX "outsourcingorder_supplier_id" ON "outsourcing_orders" ("supplier_id");
-- Create "outsourcing_order_items" table
CREATE TABLE "outsourcing_order_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "line_no" bigint NOT NULL,
  "product_no_snapshot" character varying NULL,
  "product_name_snapshot" character varying NULL,
  "process_name_snapshot" character varying NULL,
  "process_category_snapshot" character varying NULL,
  "unit_name_snapshot" character varying NULL,
  "outsourcing_quantity" numeric(20,6) NOT NULL,
  "unit_price" numeric(20,6) NULL,
  "amount" numeric(20,6) NULL,
  "expected_return_date" timestamptz NULL,
  "line_status" character varying NOT NULL DEFAULT 'open',
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "outsourcing_order_id" bigint NOT NULL,
  "process_id" bigint NOT NULL,
  "product_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "outsourcing_order_items_outsourcing_orders_items" FOREIGN KEY ("outsourcing_order_id") REFERENCES "outsourcing_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_order_items_processes_outsourcing_order_items" FOREIGN KEY ("process_id") REFERENCES "processes" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_order_items_products_outsourcing_order_items" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_order_items_units_outsourcing_order_items" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "outsourcing_order_items_amount_non_negative" CHECK ((amount IS NULL) OR (amount >= (0)::numeric)),
  CONSTRAINT "outsourcing_order_items_line_no_positive" CHECK (line_no > 0),
  CONSTRAINT "outsourcing_order_items_line_status_allowed" CHECK ((line_status)::text = ANY ((ARRAY['open'::character varying, 'closed'::character varying, 'canceled'::character varying])::text[])),
  CONSTRAINT "outsourcing_order_items_quantity_positive" CHECK (outsourcing_quantity > (0)::numeric),
  CONSTRAINT "outsourcing_order_items_unit_price_non_negative" CHECK ((unit_price IS NULL) OR (unit_price >= (0)::numeric))
);
-- Create index "outsourcingorderitem_expected_return_date" to table: "outsourcing_order_items"
CREATE INDEX "outsourcingorderitem_expected_return_date" ON "outsourcing_order_items" ("expected_return_date");
-- Create index "outsourcingorderitem_line_status" to table: "outsourcing_order_items"
CREATE INDEX "outsourcingorderitem_line_status" ON "outsourcing_order_items" ("line_status");
-- Create index "outsourcingorderitem_outsourcing_order_id_line_no" to table: "outsourcing_order_items"
CREATE UNIQUE INDEX "outsourcingorderitem_outsourcing_order_id_line_no" ON "outsourcing_order_items" ("outsourcing_order_id", "line_no");
-- Create index "outsourcingorderitem_process_id" to table: "outsourcing_order_items"
CREATE INDEX "outsourcingorderitem_process_id" ON "outsourcing_order_items" ("process_id");
-- Create index "outsourcingorderitem_product_id" to table: "outsourcing_order_items"
CREATE INDEX "outsourcingorderitem_product_id" ON "outsourcing_order_items" ("product_id");
-- Create index "outsourcingorderitem_unit_id" to table: "outsourcing_order_items"
CREATE INDEX "outsourcingorderitem_unit_id" ON "outsourcing_order_items" ("unit_id");
